(()=>{var BASE_URL=location.origin+"/";document.querySelector("head base").href=BASE_URL;document.getElementById("date").innerHTML=`&copy; ${new Date().getFullYear()} - Free for fun`;var setupInteractions=()=>{document.getElementById("content")?.addEventListener("click",e=>{let btn=e.target.closest("[data-action]");if(!btn)return;let{action,id}=btn.dataset;action==="content"&&getPage(id+".html",action,id.charAt(0).toUpperCase()+id.slice(1)),action==="modal"&&getModal(id+".html")})};document.getElementById("home").onclick=()=>getPage("home.html","content","Home");var modal=document.getElementById("modal"),modalBody=document.getElementById("modal-body"),modalCloseBtn=document.getElementById("modal-close-btn"),modalClose=()=>modal.close(),modalOpen=(msg=null,type=null)=>{msg&&(modalBody.innerHTML=msg),type&&modal.classList.add(type),modal.showModal()};modal.onclose=e=>{["text--primary","text--info","text--secondary","text--dark","text--danger","text--warning","text--success","splash"].map(e2=>modal.classList.remove(e2)),modalBody.innerHTML=null};modalCloseBtn.onclick=modalClose;var getData=async url=>{try{return await fetch(BASE_URL+url).then(res=>res.ok?res.text():Promise.reject(res))}catch(error){throw console.error("Error fetching modal content:",error),error}},getModal=async url=>{try{let data=await getData(url);modalOpen(data)}catch(error){console.error("Error fetching modal content:",error)}},getPage=async(url,id,title="Template Base")=>{document.getElementById(id).innerHTML='<div class="spinner">loading</div>',document.title=title;try{let data=await getData(url);document.getElementById(id).innerHTML=data,setupInteractions()}catch{document.getElementById(id).innerHTML="<p>Error loading content.</p>"}};var aside=document.querySelector("body aside"),asideOpen=()=>aside.classList.toggle("open"),asideClose=()=>aside.classList.remove("open");document.getElementById("menu").onclick=asideOpen;document.getElementById("close").onclick=asideClose;switch(location.hash){case"":case"#home":getPage("home.html","content","Home");break;case"#about":getPage("about.html","content","About");break;default:throw new Error("Eita!!! A rota n\xE3o existe")}})();
